'use client'
// src/components/map/Globe3D.tsx
// Full rewrite: high-detail country polygons, vivid threat arcs, clear labels

import { useEffect, useRef, useState } from 'react'

export interface GlobePoint {
  srcLat: number; srcLng: number
  dstLat: number; dstLng: number
  type: string; severity: number; label: string
  sourceUrl?: string
}

export const TYPE_COLOR: Record<string, string> = {
  Ransomware: '#ff3a5c', APT: '#c084fc', Phishing: '#fb923c',
  DDoS: '#facc15', Malware: '#f87171', Scanner: '#38bdf8',
  Threat: '#94a3b8', RAT: '#f472b6', WORM: '#fb923c',
}
const tc = (t: string) => TYPE_COLOR[t] ?? '#94a3b8'

// lat/lng → 3D unit vector
function ll2v(lat: number, lng: number, r: number): [number, number, number] {
  const phi   = (lat * Math.PI) / 180
  const theta = (lng * Math.PI) / 180
  return [
    r * Math.cos(phi) * Math.sin(theta),
    r * Math.sin(phi),
    r * Math.cos(phi) * Math.cos(theta),
  ]
}

// ─── Draw detailed world map onto canvas ──────────────────────────────────────
function drawEarth(ctx: CanvasRenderingContext2D, W: number, H: number) {
  const x = (lng: number) => ((lng + 180) / 360) * W
  const y = (lat: number) => ((90 - lat) / 180) * H

  // Deep ocean background
  const ocean = ctx.createLinearGradient(0, 0, 0, H)
  ocean.addColorStop(0, '#020d1a')
  ocean.addColorStop(0.5, '#031422')
  ocean.addColorStop(1, '#020d1a')
  ctx.fillStyle = ocean
  ctx.fillRect(0, 0, W, H)

  // Latitude / longitude grid — subtle
  ctx.strokeStyle = 'rgba(0,200,130,0.10)'
  ctx.lineWidth = 0.6
  for (let la = -80; la <= 80; la += 20) {
    ctx.beginPath(); ctx.moveTo(0, y(la)); ctx.lineTo(W, y(la)); ctx.stroke()
  }
  for (let lo = -180; lo <= 180; lo += 20) {
    ctx.beginPath(); ctx.moveTo(x(lo), 0); ctx.lineTo(x(lo), H); ctx.stroke()
  }

  // ── Land polygon helper ───────────────────────────────────────────────────
  function poly(coords: [number, number][], fill: string, stroke: string, lw = 0.9) {
    if (!coords.length) return
    ctx.beginPath()
    coords.forEach(([lo, la], i) =>
      i === 0 ? ctx.moveTo(x(lo), y(la)) : ctx.lineTo(x(lo), y(la))
    )
    ctx.closePath()
    ctx.fillStyle   = fill
    ctx.fill()
    ctx.strokeStyle = stroke
    ctx.lineWidth   = lw
    ctx.stroke()
  }

  const LAND   = 'rgba(14,90,52,0.75)'
  const BORDER = 'rgba(0,255,140,0.55)'
  const LAND2  = 'rgba(10,75,42,0.75)'   // slightly different shade for variety
  const B2     = 'rgba(0,220,120,0.45)'

  // ── NORTH AMERICA ─────────────────────────────────────────────────────────
  // Mainland
  poly([
    [-140,72],[-125,72],[-100,75],[-82,72],[-65,47],[-55,47],[-56,38],
    [-74,25],[-86,15],[-84,8],[-77,8],[-77,18],[-72,19],[-80,10],
    [-85,10],[-90,14],[-93,16],[-97,20],[-104,22],[-110,23],[-118,30],
    [-124,37],[-124,48],[-123,60],[-137,60],[-140,69],[-140,72],
  ], LAND, BORDER)
  // Alaska
  poly([
    [-168,72],[-155,72],[-148,62],[-140,60],[-137,60],[-141,68],[-160,72],[-168,72],
  ], LAND, BORDER, 0.7)
  // Greenland
  poly([
    [-52,61],[-44,58],[-24,60],[-18,70],[-20,80],[-38,84],[-58,83],
    [-68,76],[-58,70],[-52,64],[-52,61],
  ], LAND2, B2, 0.8)
  // Cuba
  poly([[-85,22],[-75,20],[-74,22],[-85,23],[-85,22]], LAND, BORDER, 0.5)

  // ── SOUTH AMERICA ─────────────────────────────────────────────────────────
  poly([
    [-80,10],[-77,8],[-62,8],[-52,5],[-36,-4],[-35,-10],[-38,-14],
    [-40,-22],[-44,-24],[-48,-28],[-52,-33],[-58,-38],[-64,-42],
    [-66,-46],[-68,-56],[-68,-58],[-72,-52],[-75,-40],[-75,-30],
    [-75,-18],[-80,0],[-80,10],
  ], LAND, BORDER)

  // ── EUROPE ────────────────────────────────────────────────────────────────
  poly([
    [-10,36],[-8,38],[-6,43],[-2,44],[0,46],[5,43],[8,44],[10,44],
    [14,42],[14,45],[10,48],[14,50],[18,55],[20,56],[25,52],[28,46],
    [30,46],[32,48],[36,46],[38,48],[30,60],[24,64],[20,66],[15,70],
    [12,64],[8,58],[5,56],[0,58],[-3,58],[-5,56],[-4,52],[-6,50],[-10,36],
  ], LAND, BORDER)
  // Scandinavia
  poly([
    [5,56],[8,57],[10,58],[10,62],[12,65],[14,68],[18,70],[22,70],
    [28,70],[30,72],[28,70],[26,65],[28,60],[24,58],[18,58],[14,56],[10,56],[5,56],
  ], LAND2, B2, 0.7)
  // Iceland
  poly([[-24,64],[-14,64],[-13,66],[-18,66],[-22,66],[-24,65],[-24,64]], LAND, BORDER, 0.5)

  // ── AFRICA ────────────────────────────────────────────────────────────────
  poly([
    [-6,36],[5,36],[10,37],[18,38],[26,34],[32,31],[36,24],[42,12],
    [44,12],[50,12],[44,10],[42,11],[36,12],[34,5],[32,0],[34,-5],
    [36,-12],[34,-22],[28,-34],[18,-34],[16,-22],[12,-5],[8,4],
    [2,6],[0,5],[-4,5],[-8,5],[-12,6],[-16,10],[-18,15],
    [-16,24],[-12,28],[-8,32],[-6,36],
  ], LAND, BORDER)
  // Madagascar
  poly([[44,-12],[50,-14],[50,-24],[44,-26],[44,-20],[44,-12]], LAND2, B2, 0.6)

  // ── ASIA WEST ─────────────────────────────────────────────────────────────
  poly([
    [28,40],[36,36],[36,24],[42,12],[50,12],[56,22],[60,22],[62,26],
    [70,22],[74,22],[78,30],[80,38],[76,44],[70,44],[64,46],[58,50],
    [52,50],[44,54],[38,50],[34,46],[30,46],[28,40],
  ], LAND, BORDER)

  // ── MIDDLE EAST & ARABIA ─────────────────────────────────────────────────
  poly([
    [36,36],[42,36],[50,30],[58,22],[58,14],[45,12],[42,12],[36,24],[36,36],
  ], LAND2, B2, 0.8)

  // ── RUSSIA (large separate polygon) ───────────────────────────────────────
  poly([
    [28,68],[40,72],[60,72],[80,74],[100,72],[120,72],[140,68],[168,68],
    [170,62],[160,60],[150,56],[142,48],[136,46],[132,48],[130,42],
    [124,40],[118,48],[110,52],[100,56],[90,56],[80,56],[72,52],[60,56],
    [50,52],[44,54],[40,56],[36,58],[32,60],[28,64],[28,68],
  ], LAND2, 'rgba(0,255,160,0.50)', 0.9)

  // Siberia / Far East extension
  poly([
    [140,68],[168,68],[180,70],[180,62],[168,62],[162,58],[156,56],
    [148,50],[142,48],[140,54],[140,60],[140,68],
  ], LAND2, B2, 0.7)

  // ── SOUTH ASIA (INDIA) ────────────────────────────────────────────────────
  poly([
    [62,24],[72,22],[78,8],[80,10],[82,16],[80,22],[78,30],[72,22],[62,24],
  ], LAND, BORDER, 0.8)
  // Indian subcontinent fuller
  poly([
    [62,24],[68,24],[72,24],[76,30],[80,30],[84,28],[88,26],[92,22],
    [90,14],[82,10],[80,8],[78,8],[72,22],[66,22],[62,24],
  ], LAND, BORDER)

  // ── CHINA & EAST ASIA ────────────────────────────────────────────────────
  poly([
    [78,44],[90,50],[100,56],[110,54],[120,52],[130,48],[132,48],[130,42],
    [122,32],[120,24],[108,20],[100,22],[94,22],[90,28],[88,26],[84,28],
    [80,30],[78,36],[80,38],[78,44],
  ], LAND, BORDER)

  // ── SOUTHEAST ASIA ────────────────────────────────────────────────────────
  poly([
    [100,22],[106,20],[104,10],[100,6],[100,2],[103,-1],[106,-4],
    [110,-8],[112,-6],[110,-2],[108,2],[104,4],[100,4],[96,6],[100,10],[100,22],
  ], LAND, BORDER, 0.8)
  // Borneo
  poly([[108,8],[118,8],[118,2],[114,-2],[108,-4],[108,2],[108,8]], LAND2, B2, 0.6)
  // Sumatra
  poly([[96,6],[104,4],[108,0],[108,-5],[100,-4],[96,2],[96,6]], LAND2, B2, 0.6)
  // Philippines
  poly([[118,18],[122,18],[124,14],[122,8],[120,10],[118,12],[118,18]], LAND2, B2, 0.6)

  // ── JAPAN ────────────────────────────────────────────────────────────────
  poly([[130,32],[132,34],[134,36],[136,36],[138,38],[140,40],[142,44],[142,42],
        [140,38],[138,36],[136,34],[132,32],[130,32]], LAND, BORDER, 0.7)

  // ── SOUTH KOREA / KOREAN PENINSULA ───────────────────────────────────────
  poly([[126,34],[128,36],[130,36],[130,38],[128,38],[126,38],[126,34]], LAND2, B2, 0.6)

  // ── AUSTRALIA ────────────────────────────────────────────────────────────
  poly([
    [114,-22],[118,-20],[122,-18],[126,-14],[130,-12],[132,-12],
    [136,-12],[138,-14],[140,-16],[142,-10],[144,-14],[148,-18],
    [152,-24],[152,-30],[150,-36],[145,-38],[138,-36],[132,-34],
    [126,-34],[116,-30],[114,-26],[114,-22],
  ], LAND, BORDER)
  // Tasmania
  poly([[144,-40],[148,-40],[148,-44],[144,-44],[144,-40]], LAND2, B2, 0.5)
  // New Zealand
  poly([[172,-40],[174,-38],[176,-36],[174,-34],[172,-36],[170,-40],[172,-40]], LAND2, B2, 0.6)
  poly([[168,-45],[170,-44],[172,-46],[170,-47],[168,-46],[168,-45]], LAND2, B2, 0.5)

  // ── CANADA detail ─────────────────────────────────────────────────────────
  poly([[-140,72],[-100,75],[-82,72],[-80,62],[-92,58],[-96,58],[-100,60],
        [-110,60],[-120,60],[-130,62],[-138,62],[-140,72]], LAND2, B2, 0.7)

  // ── ANTARCTICA ────────────────────────────────────────────────────────────
  poly([
    [-180,-70],[-90,-68],[0,-70],[90,-68],[180,-70],
    [180,-90],[-180,-90],[-180,-70],
  ], 'rgba(180,220,255,0.25)', 'rgba(200,230,255,0.4)', 0.8)

  // ── Atmospheric vignette edge ─────────────────────────────────────────────
  const vignette = ctx.createRadialGradient(W / 2, H / 2, H * 0.3, W / 2, H / 2, H * 0.7)
  vignette.addColorStop(0, 'rgba(0,0,0,0)')
  vignette.addColorStop(1, 'rgba(1,8,16,0.45)')
  ctx.fillStyle = vignette
  ctx.fillRect(0, 0, W, H)
}

// ─── Component ────────────────────────────────────────────────────────────────
interface Props { points: GlobePoint[]; height?: number; activeLayers?: Set<string> }

export function Globe3D({ points, height = 420, activeLayers }: Props) {
  const mountRef = useRef<HTMLDivElement>(null)
  const cleanRef = useRef<(() => void) | null>(null)
  const [ready, setReady] = useState(false)

  const visible = activeLayers?.size
    ? points.filter(p => activeLayers.has(p.type))
    : points

  useEffect(() => {
    cleanRef.current?.(); cleanRef.current = null
    const container = mountRef.current; if (!container) return
    let destroyed = false, animId = 0

    import('three').then(THREE => {
      if (destroyed || !container) return

      const cW = container.clientWidth  || 800
      const cH = container.clientHeight || height

      // Scene / camera
      const scene  = new THREE.Scene()
      const camera = new THREE.PerspectiveCamera(38, cW / cH, 0.01, 100)
      camera.position.set(0, 0, 3.0)

      const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true })
      renderer.setSize(cW, cH)
      renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2))
      renderer.setClearColor(0x000000, 0)
      container.appendChild(renderer.domElement)

      // ── Earth texture ──────────────────────────────────────────────────────
      const TW = 4096, TH = 2048
      const cv  = document.createElement('canvas')
      cv.width  = TW; cv.height = TH
      const ctx = cv.getContext('2d')!
      drawEarth(ctx, TW, TH)

      const earthTex       = new THREE.CanvasTexture(cv)
      earthTex.anisotropy  = renderer.capabilities.getMaxAnisotropy()

      // Globe mesh
      const R     = 1.0
      const globe = new THREE.Mesh(
        new THREE.SphereGeometry(R, 96, 96),
        new THREE.MeshPhongMaterial({
          map:              earthTex,
          shininess:        18,
          specular:         new THREE.Color(0x002208),
          emissive:         new THREE.Color(0x001a08),
          emissiveIntensity:0.18,
        })
      )
      scene.add(globe)

      // Outer atmosphere glow
      scene.add(new THREE.Mesh(
        new THREE.SphereGeometry(R * 1.06, 32, 32),
        new THREE.MeshPhongMaterial({
          color: 0x00ff88, transparent: true, opacity: 0.055, side: THREE.BackSide,
        })
      ))

      // Lights
      const ambient = new THREE.AmbientLight(0x1a3020, 5.5)
      scene.add(ambient)
      const sun = new THREE.DirectionalLight(0xbbffcc, 1.6)
      sun.position.set(5, 3, 5); scene.add(sun)
      const fill = new THREE.DirectionalLight(0x002244, 0.6)
      fill.position.set(-5, -2, -3); scene.add(fill)

      // Stars
      const sp = new Float32Array(4000 * 3)
      for (let i = 0; i < 4000 * 3; i++) sp[i] = (Math.random() - 0.5) * 40
      const sg = new THREE.BufferGeometry()
      sg.setAttribute('position', new THREE.BufferAttribute(sp, 3))
      scene.add(new THREE.Points(sg, new THREE.PointsMaterial({
        color: 0xffffff, size: 0.010, transparent: true, opacity: 0.5,
      })))

      // ── Attack arcs ────────────────────────────────────────────────────────
      const arcGroup = new THREE.Group()
      scene.add(arcGroup)

      visible.forEach(pt => {
        const color    = new THREE.Color(tc(pt.type))
        const brightColor = new THREE.Color(tc(pt.type)).multiplyScalar(1.5)
        const [sx, sy, sz] = ll2v(pt.srcLat, pt.srcLng, R)
        const [dx, dy, dz] = ll2v(pt.dstLat, pt.dstLng, R)
        const vS = new THREE.Vector3(sx, sy, sz)
        const vD = new THREE.Vector3(dx, dy, dz)

        // Arc apex: pull away from surface for visibility
        const arcHeight = 1.45 + pt.severity * 0.06
        const vM = vS.clone().add(vD).normalize().multiplyScalar(R * arcHeight)

        const curve  = new THREE.QuadraticBezierCurve3(vS, vM, vD)
        const isCrit = pt.severity >= 4
        const opacity = 0.5 + (pt.severity / 5) * 0.45

        // Fat glow tube behind the line
        arcGroup.add(new THREE.Mesh(
          new THREE.TubeGeometry(curve, 48, isCrit ? 0.010 : 0.007, 5, false),
          new THREE.MeshBasicMaterial({
            color, transparent: true, opacity: opacity * 0.25,
          })
        ))

        // Core line — bright and crisp
        arcGroup.add(new THREE.Line(
          new THREE.BufferGeometry().setFromPoints(curve.getPoints(80)),
          new THREE.LineBasicMaterial({
            color: brightColor, transparent: true, opacity: opacity,
          })
        ))

        // Source pulse dot — large and glowing
        const srcR = isCrit ? 0.036 : 0.024
        const [sx2, sy2, sz2] = ll2v(pt.srcLat, pt.srcLng, R + 0.018)
        const srcDot = new THREE.Mesh(
          new THREE.SphereGeometry(srcR, 10, 10),
          new THREE.MeshBasicMaterial({ color: brightColor })
        )
        srcDot.position.set(sx2, sy2, sz2)
        arcGroup.add(srcDot)

        // Src halo ring
        arcGroup.add(new THREE.Mesh(
          new THREE.SphereGeometry(srcR * 2.2, 10, 10),
          new THREE.MeshBasicMaterial({ color, transparent: true, opacity: 0.18 })
        ))

        // Destination dot
        const [dx2, dy2, dz2] = ll2v(pt.dstLat, pt.dstLng, R + 0.012)
        const dstDot = new THREE.Mesh(
          new THREE.SphereGeometry(0.014, 8, 8),
          new THREE.MeshBasicMaterial({ color, transparent: true, opacity: 0.8 })
        )
        dstDot.position.set(dx2, dy2, dz2)
        arcGroup.add(dstDot)
      })

      // ── Drag interaction ───────────────────────────────────────────────────
      let dragging = false, lx = 0, ly = 0
      let rotY = 0.5, rotX = 0.12, velY = 0.0020, velX = 0
      const el = renderer.domElement
      el.style.cursor = 'grab'

      const onDown  = (cx: number, cy: number) => { dragging = true; lx = cx; ly = cy; el.style.cursor = 'grabbing' }
      const onUp    = () => { dragging = false; el.style.cursor = 'grab' }
      const onMove  = (cx: number, cy: number) => {
        if (!dragging) return
        velY = (cx - lx) * 0.006; velX = (cy - ly) * 0.004
        rotY += velY; rotX += velX
        rotX = Math.max(-1.1, Math.min(1.1, rotX))
        lx = cx; ly = cy
      }

      el.addEventListener('mousedown',  e => onDown(e.clientX, e.clientY))
      el.addEventListener('touchstart', e => onDown(e.touches[0].clientX, e.touches[0].clientY), { passive: true })
      window.addEventListener('mouseup',    onUp)
      window.addEventListener('touchend',   onUp)
      window.addEventListener('mousemove',  e => onMove(e.clientX, e.clientY))
      el.addEventListener('touchmove', e => {
        e.preventDefault()
        onMove(e.touches[0].clientX, e.touches[0].clientY)
      }, { passive: false })

      const onResize = () => {
        const nW = container.clientWidth || 800
        const nH = container.clientHeight || height
        camera.aspect = nW / nH
        camera.updateProjectionMatrix()
        renderer.setSize(nW, nH)
      }
      window.addEventListener('resize', onResize)

      // ── Render loop ────────────────────────────────────────────────────────
      const animate = () => {
        if (destroyed) return
        animId = requestAnimationFrame(animate)
        if (!dragging) {
          velY += (0.0020 - velY) * 0.025
          velX *= 0.93
          rotY += velY
          rotX += velX
          rotX = Math.max(-1.1, Math.min(1.1, rotX))
        } else {
          velY *= 0.9; velX *= 0.9
        }
        globe.rotation.set(rotX, rotY, 0)
        arcGroup.rotation.set(rotX, rotY, 0)
        renderer.render(scene, camera)
      }
      animate()
      setReady(true)

      cleanRef.current = () => {
        destroyed = true
        cancelAnimationFrame(animId)
        window.removeEventListener('mouseup',   onUp)
        window.removeEventListener('touchend',  onUp)
        window.removeEventListener('resize',    onResize)
        renderer.dispose()
        earthTex.dispose()
        if (container.contains(renderer.domElement))
          container.removeChild(renderer.domElement)
      }
    }).catch(() => setReady(true))

    return () => { destroyed = true; cleanRef.current?.() }
  }, [visible.length, height])

  return (
    <div
      ref={mountRef}
      className="w-full h-full relative"
      style={{ background: 'radial-gradient(ellipse at center, #020e18 0%, #010810 100%)' }}
    >
      {!ready && (
        <div className="absolute inset-0 flex items-center justify-center">
          <span className="font-mono text-[12px] animate-pulse" style={{ color: '#00ffaa' }}>
            ⟳ Rendering 3D globe...
          </span>
        </div>
      )}
    </div>
  )
}
